    memset(dis,INF,sizeof dis);

    for(int i = 0;i<row;i++){

        for(int j = 0;j<col;j++){

            cin>>map[i][j];

            if(map[i][j] == 'S'){

                //设置起点

                q.push(pos(i,j));

                dis[i][j] = 0;

            }

        }

    }

    //开始广搜

    bfs();

    cout<<ans<<endl;

    return 0;

}

